(function($){'use strict';$('.elcProQuiz_editQuizLink').each(function(){let data_quiz_meta_json=this.dataset.quizMeta;let quiz_pro_id=$.parseJSON(data_quiz_meta_json).quiz_pro_id;$(this).insertBefore('#wpProQuiz_'+quiz_pro_id+' .wpProQuiz_text').show()});const elcPostIdSelector='#learndash_post_'+elcQuizEmbed.post_id;const elcHideActions=elcQuizEmbed.hide_actions;const hideContentList=function(){let selector;if(elcQuizEmbed.post_type==='sfwd-courses'){selector=elcPostIdSelector+' .ld-course-content-'+elcQuizEmbed.post_id}else{selector=elcPostIdSelector+' .ld-topic-list'}
if($(selector).length){$(selector).hide()}};const hideContentActions=function(){let selector=elcPostIdSelector+' .ld-content-actions';if($(selector).length){$(selector).hide()}};$(document).ready(function(){if(!$('body').hasClass('single-sfwd-quiz')&&elcHideActions==='1'){const observeQuizzes=function(){let proQuizzes=$('.wpProQuiz_list');let loadQuiz=$('.wpProQuiz_loadQuiz');if(proQuizzes.length>0&&proQuizzes.length===loadQuiz.length){proQuizzes.each(function(){ro.observe($(this).get(0))})}else{loadQuiz.each(function(){let element=$(this).get(0);if($(this).siblings('.wpProQuiz_quiz').length){let wpProQuizList=$('.wpProQuiz_list');element=$(this).siblings('.wpProQuiz_quiz').find(wpProQuizList).get(0)}
ro.observe(element)})}}
const ro=new ResizeObserver(elements=>{for(let elem of elements){let height=Math.floor(elem.contentRect.height);if(elem.target.className==='wpProQuiz_list'&&height>0){hideContentList();hideContentActions();ro.disconnect()}else if(elem.target.className==='wpProQuiz_loadQuiz'&&height===0){observeQuizzes()}}});observeQuizzes()}})})(jQuery)